import time
import sys
import random

# ANSI escape codes
RESET = "\033[0m"
BOLD = "\033[1m"
DIM = "\033[2m"
ITALIC = "\033[3m"
UNDERLINE = "\033[4m"
BLINK = "\033[5m"
REVERSE = "\033[7m"

# Colors
RED = "\033[91m"
GREEN = "\033[92m"
YELLOW = "\033[93m"
BLUE = "\033[94m"
MAGENTA = "\033[95m"
CYAN = "\033[96m"
WHITE = "\033[97m"
GRAY = "\033[90m"

# Backgrounds
BG_BLACK = "\033[40m"
BG_RED = "\033[41m"
BG_GREEN = "\033[42m"
BG_YELLOW = "\033[43m"
BG_BLUE = "\033[44m"
BG_MAGENTA = "\033[45m"
BG_CYAN = "\033[46m"
BG_WHITE = "\033[47m"

def slow_print(text, delay=0.03, color=""):
    """Print text character by character with a delay"""
    for char in text:
        sys.stdout.write(f"{color}{char}{RESET}")
        sys.stdout.flush()
        time.sleep(delay)
    print()

def clear_screen():
    """Clear the terminal screen"""
    print("\033[2J\033[H", end="")

def move_cursor(row, col):
    """Move cursor to specific position"""
    print(f"\033[{row};{col}H", end="")

def draw_box(width, height, row, col, color):
    """Draw a box at specific position"""
    # Top border
    move_cursor(row, col)
    print(f"{color}╔{'═' * (width - 2)}╗{RESET}")
    
    # Sides
    for i in range(height - 2):
        move_cursor(row + 1 + i, col)
        print(f"{color}║{' ' * (width - 2)}║{RESET}")
    
    # Bottom border
    move_cursor(row + height - 1, col)
    print(f"{color}╚{'═' * (width - 2)}╝{RESET}")

def animate_loading():
    """Show a loading animation"""
    frames = ["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"]
    for i in range(20):
        sys.stdout.write(f"\r{CYAN}Contemplating the meaning of existence... {frames[i % len(frames)]}{RESET}")
        sys.stdout.flush()
        time.sleep(0.1)
    print()

