def print_quote_box(quote, author="Woody Allen"):
    """Print a quote in a fancy box"""
    # Split quote into lines
    words = quote.split()
    lines = []
    current_line = ""
    
    for word in words:
        if len(current_line) + len(word) + 1 <= 50:
            current_line += " " + word if current_line else word
        else:
            lines.append(current_line)
            current_line = word
    if current_line:
        lines.append(current_line)
    
    # Find the longest line
    max_len = max(len(line) for line in lines)
    box_width = max_len + 6
    
    # Print the box
    print(f"\n{CYAN}  ╔{'═' * box_width}╗{RESET}")
    print(f"{CYAN}  ║{' ' * box_width}║{RESET}")
    
    for line in lines:
        padding = (box_width - len(line)) // 2
        extra = (box_width - len(line)) % 2
        print(f"{CYAN}  ║{RESET}  {' ' * padding}{YELLOW}{line}{' ' * (padding + extra)}{RESET}  {CYAN}║{RESET}")
    
    print(f"{CYAN}  ║{' ' * box_width}║{RESET}")
    
    # Author line
    author_text = f"— {author}"
    author_padding = box_width - len(author_text) - 2
    print(f"{CYAN}  ║{RESET}{' ' * author_padding}{DIM}{ITALIC}{author_text}{RESET}  {CYAN}║{RESET}")
    
    print(f"{CYAN}  ║{' ' * box_width}║{RESET}")
    print(f"{CYAN}  ╚{'═' * box_width}╝{RESET}\n")

